for ($i=0; $i -lt 20; $i++) {
    $runList = gh run list --branch branch-v1.5.0-dev --json status,conclusion,name,databaseId,url --limit 5 | ConvertFrom-Json
    $workflowRun = $runList | Where-Object { $_.name -eq "CI/CD — Dashboard Mictlan (consolidated)" }

    if ($workflowRun) {
        if ($workflowRun.status -eq "completed") {
            if ($workflowRun.conclusion -eq "success") {
                Write-Host "Workflow completed successfully!"
                gh run view $($workflowRun.databaseId) --json jobs > C:\Users\acodu\.gemini\tmp\dashboard-mictlan\run_jobs.json
                $runId = $($workflowRun.databaseId)
                break
            } elseif ($workflowRun.conclusion -eq "failure") {
                Write-Host "Workflow failed. URL: $($workflowRun.url)"
                exit 1
            }
        } else {
            Write-Host "Workflow status: $($workflowRun.status). Waiting..."
        }
    } else {
        Write-Host "Workflow not found yet. Waiting..."
    }
    Start-Sleep -Seconds 30
}

for ($i=0; $i -lt 20; $i++) {
